{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"\\d \\\"case\\\"\"",
  "description": "Check case table schema"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/core_crm.db' \".schema Account\"",
  "description": "Check Account schema"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"\\dt\"",
  "description": "List tables"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/core_crm.db' \".schema Account\"",
  "description": "Check Account schema"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c '\\d \"Case\"'",
  "description": "Case table schema"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/core_crm.db' \"SELECT DISTINCT ShippingState FROM Account LIMIT 30;\"",
  "description": "Sample ShippingState values"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT MIN(createddate), MAX(createddate) FROM \\\"Case\\\";\"",
  "description": "Check date range of cases"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT COUNT(*) FROM \\\"Case\\\" WHERE closeddate IS NOT NULL AND createddate >= '2021-04-01' AND createddate < '2022-10-01';\"",
  "description": "Count cases in past 6 quarters"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT status, COUNT(*) FROM \\\"Case\\\" GROUP BY status;\"",
  "description": "Check case statuses"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT COUNT(*) FROM \\\"Case\\\" WHERE closeddate IS NOT NULL;\"",
  "description": "Total closed cases"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c \"SELECT createddate, closeddate FROM \\\"Case\\\" WHERE closeddate IS NOT NULL ORDER BY createddate LIMIT 10;\"",
  "description": "Sample closed case dates"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -c "COPY (
SELECT c.accountid, c.createddate, c.closeddate
FROM \"Case\" c
WHERE c.closeddate IS NOT NULL 
  AND c.createddate >= '2021-04-01' 
  AND c.createddate < '2022-10-01'
) TO STDOUT WITH CSV HEADER;"",
  "description": "Export closed cases"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/core_crm.db' \"SELECT Id, ShippingState FROM Account WHERE Id IN ('001Wt00000PGRnYIAX', '#001Wt00000PGRnYIAX', '001Wt00000PGtmwIAD');\"",
  "description": "Check account IDs with/without hash prefix"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -t -A -F',' -c \"SELECT REPLACE(c.accountid, '#', '') AS accountid, EXTRACT(EPOCH FROM (TO_TIMESTAMP(SUBSTRING(c.closeddate, 1, 19), 'YYYY-MM-DD\\\"T\\\"HH24:MI:SS') - TO_TIMESTAMP(SUBSTRING(c.createddate, 1, 19), 'YYYY-MM-DD\\\"T\\\"HH24:MI:SS'))) AS closure_seconds FROM \\\"Case\\\" c WHERE c.closeddate IS NOT NULL AND c.createddate >= '2021-04-01' AND c.createddate < '2022-10-01';\" > /tmp/cases.csv && cat /tmp/cases.csv | head -3",
  "description": "Export cases to CSV"
}

{
  "command": "sqlite3 '/Users/shreyashankar/Documents/projects/DataAgentBench/query_crmarenapro/query_dataset/core_crm.db' \"SELECT Id, ShippingState FROM Account WHERE Id LIKE '%PHHXXIA5%' OR Id LIKE '%PGdzxIAD%' OR Id LIKE '%PGaZCIA1%' OR Id LIKE '%PHR8gIAH%' OR Id LIKE '%PGXrLIAX%';\"",
  "description": "Search for missing IDs"
}

{
  "command": "psql -h 127.0.0.1 -U shreyashankar -d crm_support -t -A -F'|' -c \"SELECT c.accountid, EXTRACT(EPOCH FROM (TO_TIMESTAMP(SUBSTRING(c.closeddate, 1, 19), 'YYYY-MM-DD\\\"T\\\"HH24:MI:SS') - TO_TIMESTAMP(SUBSTRING(c.createddate, 1, 19), 'YYYY-MM-DD\\\"T\\\"HH24:MI:SS'))) AS closure_seconds FROM \\\"Case\\\" c WHERE c.closeddate IS NOT NULL AND c.createddate >= '2021-04-01' AND c.createddate < '2022-10-01';\" > /tmp/cases2.csv && cat /tmp/cases2.csv | head -3",
  "description": "Export with original accountid"
}
